import { useState } from "react";

function App() {
  const [cart, setCart] = useState([]);
  const [showOrderForm, setShowOrderForm] = useState(false);
  const [order, setOrder] = useState({
    name: "",
    phone: "",
    address: "",
    branch: "Kolkata",
  });

  const sweets = [
    {
      id: 1,
      name: "Rasgulla",
      bengali: "রসগোল্লা",
      price: 15,
      category: "Sponge",
      branch: "Tamluk",
      rating: 4.9,
      image:
        "data:image/jpeg;base64,",
    },
    {
      id: 2,
      name: "Sandesh",
      bengali: "সন্দেশ",
      price: 12,
      category: "Fresh",
      branch: "Tamluk",
      rating: 4.8,
      image:
        "data:image/jpeg;base64,",
    },
    {
      id: 3,
      name: "Mishti Doi",
      bengali: "মিষ্টি দই",
      price: 40,
      category: "Creamy",
      branch: "Tamluk",
      rating: 4.7,
      image:
        "data:image/jpeg;base64,",
    },
    {
      id: 4,
      name: "Chomchom",
      bengali: "চমচম",
      price: 20,
      category: "Sponge",
      branch: "Tamluk",
      rating: 4.6,
      image:
        "data:image/jpeg;base64,",
    },
    {
      id: 5,
      name: "Rasmalai",
      bengali: "রসমালাই",
      price: 20,
      category: "Creamy",
      branch: "Tamluk",
      rating: 4.9,
      image:
        "data:image/jpeg;base64,",
    },
    {
      id: 6,
      name: "Pitha",
      bengali: "পিঠা",
      price: 20,
      category: "Traditional",
      branch: "Tamluk",
      rating: 4.7,
      image:
        "data:image/jpeg;base64,",
    },
  ];

  const branches = [
    "Tamluk",
    "Hospital More ",
    "Radhaballavpur",
    "Nimtouri",
    "Maniktala",
  ];

  const addToCart = (sweet) => {
 const existing = cart.find((item) => item.id === sweet.id);

  if (existing) {
    setCart(
      cart.map((item) =>
        item.id === sweet.id
          ? { ...item, quantity: item.quantity + 1 }
          : item
      )
    );
  } else {
    setCart([...cart, { ...sweet, quantity: 1 }]);
  }
};


  const increaseQty = (id) => {
  setCart(
    cart.map((item) =>
      item.id === id ? { ...item, quantity: item.quantity + 1 } : item
    )
  );
};

const decreaseQty = (id) => {
  setCart(
    cart
      .map((item) =>
        item.id === id ? { ...item, quantity: item.quantity - 1 } : item
      )
      .filter((item) => item.quantity > 0)
  );
};


 const items = cart
  .map((i) => `${i.name} x ${i.quantity}`)
  .join(", ");

const totalPrice = cart.reduce(
  (sum, i) => sum + i.price * i.quantity,
  0
);

const message = `New Order:
Name: ${order.name}
Phone: ${order.phone}
Address: ${order.address}
Branch: ${order.branch}

Items: ${items}
Total: ₹${totalPrice}`;

  const sendOrder = () => {
    setOrder({ name: "", phone: "", address: "", branch: "Tamluk" });
    
    setShowOrderForm(false);
    alert("Order sent to WhatsApp! 📱");
  };


  const submitOrder = (e) => {
  e.preventDefault();

  if (!order.name || !order.phone || !order.address || cart.length === 0) {
    alert("Please fill all fields and add items!");
    return;
  }

  const items = cart
    .map((i) => `${i.name} x ${i.quantity}`)
    .join(", ");

  const totalPrice = cart.reduce(
    (sum, i) => sum + i.price * i.quantity,
    0
  );

  const message = `New Order:
Name: ${order.name}
Phone: ${order.phone}
Address: ${order.address}
Branch: ${order.branch}

Items: ${items}
Total: ₹${totalPrice}`;

  window.open(
    `https://wa.me/919337602150?text=${encodeURIComponent(message)}`
  );

  setCart([]);
  setShowOrderForm(false);
};

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 via-orange-50 to-yellow-50">
      {/* Navigation */}
      <nav className="bg-white/95 backdrop-blur-xl shadow-xl sticky top-0 z-50 border-b border-pink-100">
        <div className="max-w-7xl mx-auto px-6 py-5 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-14 h-14 bg-gradient-to-r from-pink-500 to-orange-500 rounded-3xl flex items-center justify-center shadow-2xl animate-pulse">
              <span className="text-3xl">🍬</span>
            </div>
            <div>
              <h1 className="text-2xl font-black bg-gradient-to-r from-pink-600 to-orange-600 bg-clip-text text-transparent">
                Sweet
              </h1>
              <p className="text-xs text-gray-500 font-medium">
                Authentic Bengali Sweets
              </p>
            </div>
          </div>

          <div className="flex items-center space-x-4">
            <button
              onClick={() => setShowOrderForm(true)}
              className="bg-gradient-to-r from-green-500 to-emerald-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg hover:shadow-xl hover:scale-105 transition-all duration-300"
            >
              🛒 Cart ({cart.reduce((sum, item) => sum + item.quantity, 0)})
            </button>
            <a
              href="tel:+919337602150"
              className="flex items-center space-x-2 bg-gradient-to-r from-pink-500 to-orange-500 text-white px-8 py-3 rounded-2xl font-bold shadow-lg hover:shadow-xl hover:scale-105 transition-all"
            >
              <span>📞 Call</span>
            </a>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative py-32 px-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-pink-600/90 via-orange-500/90 to-yellow-500/90"></div>
        <div className="relative z-10 max-w-5xl mx-auto text-center text-white">
          <h1 className="text-5xl md:text-7xl font-black mb-8 leading-tight">
            Fresh{" "}
            <span className="block text-6xl md:text-8xl bg-white/30 px-8 py-4 rounded-3xl mx-auto max-w-4xl">
              Bengali Sweets
            </span>
          </h1>
          <p className="text-xl md:text-2xl mb-12 opacity-95 max-w-3xl mx-auto leading-relaxed">
            Authentic Rasgulla, Sandesh, Mishti Doi made daily with pure cow
            milk. Delivered across West Bengal!
          </p>
          <div className="flex flex-col sm:flex-row gap-6 justify-center items-center max-w-2xl mx-auto mb-16">
            <button
              onClick={() =>
                document
                  .getElementById("products")
                  .scrollIntoView({ behavior: "smooth" })
              }
              className="bg-white text-pink-600 px-12 py-5 rounded-3xl font-bold text-xl shadow-2xl hover:shadow-3xl hover:scale-105 transition-all duration-300 w-full sm:w-auto"
            >
              🍬 Explore Menu
            </button>
            <a
              href="tel:+919337602150"
              className="bg-transparent border-4 border-white text-white px-12 py-5 rounded-3xl font-bold text-xl hover:bg-white hover:text-pink-600 transition-all duration-300 w-full sm:w-auto"
            >
              Order Now 📞
            </a>
          </div>

          {/* Trust Badges */}
          <div className="flex flex-wrap justify-center items-center gap-12 text-lg opacity-90">
            <div className="flex items-center space-x-3 p-4 bg-white/20 rounded-2xl backdrop-blur-sm">
              <span className="text-2xl">⭐</span>
              <span>4.9 (2K+)</span>
            </div>
            <div className="flex items-center space-x-3 p-4 bg-white/20 rounded-2xl backdrop-blur-sm">
              <span className="text-2xl">🚚</span>
              <span>30 Min</span>
            </div>
            <div className="flex items-center space-x-3 p-4 bg-white/20 rounded-2xl backdrop-blur-sm">
              <span className="text-2xl">💯</span>
              <span>Fresh Daily</span>
            </div>
          </div>
        </div>
      </section>

      {/* Products Section */}
      <section id="products" className="py-24 px-6">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-20">
            <h2 className="text-4xl md:text-6xl font-black mb-6 bg-gradient-to-r from-gray-800 to-gray-600 bg-clip-text text-transparent">
              Our Delicious Sweets
            </h2>
            <p className="text-xl text-gray-600 max-w-3xl mx-auto">
              Freshly made with love and authentic Bengali recipes
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
            {sweets.map((sweet) => (
              <div
                key={sweet.id}
                className="group bg-white rounded-3xl shadow-xl hover:shadow-2xl overflow-hidden hover:-translate-y-4 transition-all duration-500 cursor-pointer hover:rotate-1"
              >
                <div className="relative h-80 overflow-hidden bg-gradient-to-br from-yellow-50 to-orange-50">
                  <img
                    src={sweet.image}
                    alt={sweet.name}
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                    loading="lazy"
                  />
                  <div className="absolute top-6 right-6 p-3 bg-white/95 rounded-3xl shadow-2xl opacity-0 group-hover:opacity-100 transition-all duration-300 scale-0 group-hover:scale-100">
                    <span className="text-2xl">❤️</span>
                  </div>
                  <div className="absolute top-6 left-6 px-4 py-2 bg-green-500 text-white rounded-2xl font-bold text-sm shadow-lg">
                    Fresh
                  </div>
                </div>

                <div className="p-8">
                  <div className="flex items-start justify-between mb-4">
                    <h3 className="text-2xl font-bold text-gray-800 line-clamp-2">
                      {sweet.name}
                    </h3>
                    <div className="text-3xl font-black bg-gradient-to-r from-pink-500 to-orange-500 bg-clip-text text-transparent">
                      ₹{sweet.price}
                    </div>
                  </div>

                  <p className="text-pink-600 font-semibold mb-3 text-lg">
                    {sweet.bengali}
                  </p>

                  <div className="flex items-center mb-6">
                    <span className="text-2xl">⭐</span>
                    <span className="ml-2 font-bold text-lg">
                      {sweet.rating}
                    </span>
                    <span className="ml-4 text-sm text-gray-500 font-medium">
                      ({sweet.branch})
                    </span>
                  </div>

                  <button
                    onClick={() => addToCart(sweet)}
                    className="w-full bg-gradient-to-r from-pink-500 to-orange-500 text-white py-4 px-8 rounded-2xl font-bold text-lg shadow-xl hover:shadow-2xl transform hover:-translate-y-1 hover:scale-[1.02] transition-all duration-300"
                  >
                    Add to Cart 🛒
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Stats Section */}
      <section className="py-24 bg-gradient-to-r from-pink-500/20 via-orange-500/20 to-yellow-500/20 backdrop-blur-sm">
        <div className="max-w-6xl mx-auto px-6 grid grid-cols-1 md:grid-cols-3 gap-16 text-center">
          <div className="transform hover:scale-105 transition-all duration-300">
            <div className="text-6xl font-black mb-6 bg-gradient-to-r from-yellow-400 to-orange-400 bg-clip-text text-transparent">
              4.9⭐
            </div>
            <div className="text-2xl font-bold text-gray-800">
              Customer Rating
            </div>
          </div>
          <div className="transform hover:scale-105 transition-all duration-300">
            <div className="text-6xl font-black mb-6 bg-gradient-to-r from-green-400 to-emerald-400 bg-clip-text text-transparent">
              5K+
            </div>
            <div className="text-2xl font-bold text-gray-800">
              Happy Customers
            </div>
          </div>
          <div className="transform hover:scale-105 transition-all duration-300">
            <div className="text-6xl font-black mb-6 bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent">
              30 Min
            </div>
            <div className="text-2xl font-bold text-gray-800">Delivery</div>
          </div>
        </div>
      </section>

      {/* Branches */}
      <section className="py-24 px-6 bg-white/50">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-20">
            <h2 className="text-4xl md:text-6xl font-black mb-6 bg-gradient-to-r from-gray-800 to-gray-600 bg-clip-text text-transparent">
              Our Branches
            </h2>
            <p className="text-xl text-gray-600">Serving West Bengal</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6">
            {branches.map((branch, index) => (
              <div
                key={index}
                className="group p-8 bg-gradient-to-br from-white to-pink-50 rounded-3xl shadow-xl hover:shadow-2xl hover:-translate-y-3 transition-all duration-500 border border-pink-100"
              >
                <div className="text-4xl mb-6">
                  {["🏪", "🛒", "🍬", "⭐", "📍"][index % 5]}
                </div>
                <h3 className="text-2xl font-bold text-gray-800 mb-4">
                  {branch}
                </h3>
                <p className="text-gray-600 mb-6">Fast delivery available</p>
                <button className="w-full bg-gradient-to-r from-pink-500 to-orange-500 text-white py-4 rounded-2xl font-bold hover:shadow-xl transition-all">
                  Order from {branch}
                </button>
              </div>
            ))}
          </div>
        </div>
      </section>

       <div className="mb-4">
  {cart.length === 0 ? (
    <p>No items added</p>
  ) : (
    cart.map((item) => (
      <div key={item.id} className="flex justify-between items-center mb-2">
        <span>{item.name}</span>

        <div className="flex gap-2">
          <button onClick={() => decreaseQty(item.id)}>-</button>
          <span>{item.quantity}</span>
          <button onClick={() => increaseQty(item.id)}>+</button>
        </div>

        <span>₹{item.price * item.quantity}</span>
      </div>
    ))
  )}
</div>


        
      {/* Order Modal */}
      {showOrderForm && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-3xl shadow-2xl max-w-md w-full max-h-[90vh] overflow-y-auto">
            <div className="p-8 border-b border-gray-100">
              <h2 className="text-3xl font-bold text-gray-800 mb-2">
                Complete Order
              </h2>
              <p className="text-xl font-semibold text-green-600">
               Total Items: {cart.reduce((sum, item) => sum + item.quantity, 0)}
              </p>
            </div>

    <div className="mb-4">
  {cart.length === 0 ? (
    <p>No items added</p>
  ) : (
    cart.map((item) => (
      <div key={item.id} className="flex justify-between items-center mb-2">
        <span>{item.name} x {item.quantity}</span>
        <span>₹{item.price * item.quantity}</span>
      </div>
    ))
  )}
</div>


            <form onSubmit={submitOrder} className="p-8 space-y-6">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">
                  Full Name
                </label>
                <input
                  type="text"
                  value={order.name}
                  onChange={(e) => setOrder({ ...order, name: e.target.value })}
                  className="w-full p-4 border border-gray-300 rounded-2xl focus:ring-4 focus:ring-pink-200 focus:border-pink-500 transition-all"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">
                  Phone
                </label>
                <input
                  type="tel"
                  value={order.phone}
                  onChange={(e) =>
                    setOrder({ ...order, phone: e.target.value })
                  }
                  className="w-full p-4 border border-gray-300 rounded-2xl focus:ring-4 focus:ring-green-200 focus:border-green-500 transition-all"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">
                  Address
                </label>
                <textarea
                  value={order.address}
                  onChange={(e) =>
                    setOrder({ ...order, address: e.target.value })
                  }
                  rows="3"
                  className="w-full p-4 border border-gray-300 rounded-2xl focus:ring-4 focus:ring-blue-200 focus:border-blue-500 transition-all resize-none"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">
                  Branch
                </label>
                <select
                  value={order.branch}
                  onChange={(e) =>
                    setOrder({ ...order, branch: e.target.value })
                  }
                  className="w-full p-4 border border-gray-300 rounded-2xl focus:ring-4 focus:ring-purple-200 focus:border-purple-500 transition-all"
                >
                  {branches.map((b) => (
                    <option key={b} value={b}>
                      {b}
                    </option>
                  ))}
                </select>
              </div>

              <div className="flex gap-4 pt-4">
                <button
                  type="button"
                  onClick={() => setShowOrderForm(false)}
                  className="flex-1 bg-gray-200 text-gray-800 py-4 px-8 rounded-2xl font-bold hover:bg-gray-300 transition-all"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="flex-1 bg-gradient-to-r from-green-500 to-emerald-600 text-white py-4 px-8 rounded-2xl font-bold hover:shadow-xl transition-all"
                >
                  Order via WhatsApp 📱
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
